const mode = env.get('mode');
const address = env.get('address');
const reg = env.get('register');
const val = env.get('value');

if (!['read', 'write'].includes(mode)) {
    node.error(`invalid mode: ${mode}, expected 'read' or 'write'`, msg);
    return null;
}

msg._mode = mode;
msg._address = address;
msg._register = reg;
msg._value = val;

// i2cget/i2cset from i2c-tools, bus 1.
if (mode === 'read') {
    msg.payload = `i2cget -y 1 ${address} ${reg}`;
} else {
    msg.payload = `i2cset -y 1 ${address} ${reg} ${val}`;
}
return msg;

const rc = msg.rc && typeof msg.rc.code === 'number' ? msg.rc.code : null;
const text = (typeof msg.payload === 'string') ? msg.payload.trim() : '';

if (rc === null) {
    msg._buf = (msg._buf || '') + text;
    return null;
}

const output = (msg._buf || '').trim();
let result = {
    success: rc === 0,
    mode: msg._mode,
    address: msg._address,
    register: msg._register,
    exit_code: rc,
    timestamp: new Date().toISOString()
};

if (msg._mode === 'read' && rc === 0) {
    result.value = output;  // e.g. '0x2a'
} else if (msg._mode === 'write') {
    result.value_written = msg._value;
} else {
    result.error = output;
}

msg.payload = result;

delete msg._mode;
delete msg._address;
delete msg._register;
delete msg._value;
delete msg._buf;
return msg;
